<template>
  <div>
    <!-- ./img/bg.jpg -->
    <img v-for="i in imgList" :key="i.id" :src="i.src" alt="" :class="i.clas">
  </div>
</template>

<script>
export default {
  name: 'HelloWorld',
  data() {
    return {
      imgList:[
        {id:"img1",src:require("./img/01.jpg"),clas:'img1'},
        {id:"img2",src:require("./img/02.jpg"),clas:'img2'},
        {id:"img3",src:require("./img/03.jpg"),clas:'img3'},
        {id:"img4",src:require("./img/04.jpg"),clas:'img4'},
        {id:"img5",src:require("./img/05.jpg"),clas:'img5'},
        {id:"img6",src:require("./img/06.jpg"),clas:'img6'},
        {id:"img7",src:require("./img/07.jpg"),clas:'img7'},
        {id:"img8",src:require("./img/08.jpg"),clas:'img8'},
        {id:"img9",src:require("./img/09.jpg"),clas:'img9'},
        {id:"img10",src:require("./img/10.jpg"),clas:'img10'}
      ],
    };
  },
  methods: {
    gogo(){
      let endClass=this.imgList[this.imgList.length-1].clas;
      for(let i=this.imgList.length-1;i>0;i--){
        this.imgList[i].clas=this.imgList[i-1].clas;
      }
      this.imgList[0].clas=endClass;
    }
  },
  mounted () {
    setInterval(this.gogo,2500)
  }
 
}
</script>

